SELECT D.DEPT_ID ,D.DEPT_NM ,D.UP_DEPT_ID ,D.CO_ID ,D.SORT_SEQ ,D.DEPT_SE_CD ,D.DEPT_EXPLN ,D.MNGR_USER_ID ,D.USE_YN ,D.REG_DT ,PD.DEPT_NM AS UP_DEPT_NM ,M.USER_NM AS MNGR_USER_NM ,M.JBPS_NM AS MNGR_JBPS_NM FROM dept_info D LEFT JOIN dept_info PD ON D.UP_DEPT_ID = PD.DEPT_ID LEFT JOIN user_info M ON D.MNGR_USER_ID = M.USER_ID WHERE D.USE_YN = 'Y'
AND D.CO_ID = #{coId}
ORDER BY D.SORT_SEQ ASC, D.DEPT_ID ASC

